import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaEnvelope, FaLock } from 'react-icons/fa';

const LoginPage = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    const res = await loginAdmin(email, password);
    if (res.data.access_token) {
      onLogin(res.data.access_token);
    }
  };

  return (
    <div style={{
      height: "100vh",
      display: "flex"
    }}>

      {/* LEFT SIDE */}
      <div style={{
        flex: 1,
        background: "#f5f7fb",
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        padding: "60px"
      }}>
        <h1 style={{ fontSize: "40px", lineHeight: "1.3" }}>
          AI-Powered <br />
          <span style={{ color: "#2563EB" }}>Resume Screening</span>
          <br /> Made Simple
        </h1>

        <p style={{ marginTop: "20px", color: "#555" }}>
          Analyze and hire candidates faster using AI.
        </p>
      </div>

      {/* RIGHT SIDE LOGIN */}
      <div style={{
        flex: 1,
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "white"
      }}>
        <div style={{
          width: "350px",
          padding: "30px",
          borderRadius: "15px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.1)"
        }}>

          <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
            Admin Login
          </h2>

          <form onSubmit={handleSubmit}>

            {/* Email */}
            <div style={{ marginBottom: "15px", position: "relative" }}>
              <FaEnvelope style={{ position: "absolute", top: "12px", left: "10px" }} />
              <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{
                  width: "100%",
                  padding: "10px 10px 10px 35px",
                  borderRadius: "8px",
                  border: "1px solid #ccc"
                }}
              />
            </div>

            {/* Password */}
            <div style={{ marginBottom: "20px", position: "relative" }}>
              <FaLock style={{ position: "absolute", top: "12px", left: "10px" }} />
              <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{
                  width: "100%",
                  padding: "10px 10px 10px 35px",
                  borderRadius: "8px",
                  border: "1px solid #ccc"
                }}
              />
            </div>

            {/* Button */}
            <button style={{
              width: "100%",
              padding: "12px",
              background: "#2563EB",
              color: "white",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer"
            }}>
              Login
            </button>

          </form>

        </div>
      </div>

    </div>
  );
};

export default LoginPage;
